    29→
    30→const (
    31→	// defaultConfigPath is the default path for application tagging configuration
    32→	defaultConfigPath = "./var/tagger/apps"
    33→	// tagTypeApp is the tag type identifier for application tags
    34→	tagTypeApp = "app"
    35→	// configDirMatch is the directory name used for matching filesystem events
    36→	configDirMatch = "apps"
    37→)
    38→
    39→type appInfo struct {
    40→	tag      string
    41→	patterns []*regexp.Regexp
    42→}
    43→
    44→// AppTagger detects applications by matching patterns in job scripts.
    45→// It loads application patterns from an external configuration directory and can dynamically reload
    46→// configuration when files change. When a job script matches a pattern,
    47→// the corresponding application tag is automatically applied.
    48→type AppTagger struct {
    49→	// apps holds application patterns in deterministic order
    50→	apps []appInfo
    51→	// tagType is the type of tag ("app")
    52→	tagType string
    53→	// cfgPath is the path to watch for configuration changes
    54→	cfgPath string
    55→}
    56→
    57→func (t *AppTagger) scanApp(f *os.File, fns string) {
    58→	scanner := bufio.NewScanner(f)
    59→	tag := strings.TrimSuffix(fns, filepath.Ext(fns))
    60→	ai := appInfo{tag: tag, patterns: make([]*regexp.Regexp, 0)}
    61→
    62→	for scanner.Scan() {
    63→		line := strings.TrimSpace(scanner.Text())
    64→		if line == "" {
    65→			continue
    66→		}
    67→		// Wrap pattern to skip comment lines: match only if not preceded by # on the same line
    68→		wrapped := `(?m)^[^#]*` + line
    69→		re, err := regexp.Compile(wrapped)
    70→		if err != nil {
    71→			cclog.Errorf("invalid regex pattern '%s' (wrapped: '%s') in %s: %v", line, wrapped, fns, err)
    72→			continue
    73→		}
    74→		ai.patterns = append(ai.patterns, re)
    75→	}
    76→
    77→	// Remove existing entry for this tag if present
    78→	for i, a := range t.apps {
    79→		if a.tag == tag {
    80→			t.apps = append(t.apps[:i], t.apps[i+1:]...)
    81→			break
    82→		}
    83→	}
    84→
    85→	cclog.Infof("AppTagger loaded %d patterns for %s", len(ai.patterns), tag)
    86→	t.apps = append(t.apps, ai)
    87→}
    88→
    89→// EventMatch checks if a filesystem event should trigger configuration reload.
    90→// It returns true if the event path contains "apps".
    91→func (t *AppTagger) EventMatch(s string) bool {
    92→	return strings.Contains(s, configDirMatch)
    93→}
    94→
    95→// EventCallback is triggered when the configuration directory changes.
    96→// It reloads all application pattern files from the watched directory.
    97→func (t *AppTagger) EventCallback() {
    98→	files, err := os.ReadDir(t.cfgPath)
    99→	if err != nil {
   100→		cclog.Fatal(err)
   101→	}
   102→
   103→	t.apps = make([]appInfo, 0)
   104→
   105→	for _, fn := range files {
   106→		if fn.IsDir() {
   107→			continue
   108→		}
   109→		fns := fn.Name()
   110→		cclog.Debugf("Process: %s", fns)
   111→		f, err := os.Open(filepath.Join(t.cfgPath, fns))
   112→		if err != nil {
   113→			cclog.Errorf("error opening app file %s: %#v", fns, err)
   114→			continue
   115→		}
   116→		t.scanApp(f, fns)
   117→		if err := f.Close(); err != nil {
   118→			cclog.Errorf("error closing app file %s: %#v", fns, err)
   119→		}
   120→	}
   121→}
   122→
   123→// Register initializes the AppTagger by loading application patterns from external folder.
   124→// It sets up a file watch on ./var/tagger/apps if it exists, allowing for
   125→// dynamic configuration updates without restarting the application.
   126→// Returns an error if the configuration path does not exist or cannot be read.
   127→func (t *AppTagger) Register() error {
   128→	if t.cfgPath == "" {
   129→		t.cfgPath = defaultConfigPath
   130→	}
   131→	t.tagType = tagTypeApp
   132→	t.apps = make([]appInfo, 0)
   133→
   134→	if !util.CheckFileExists(t.cfgPath) {
   135→		return fmt.Errorf("configuration path does not exist: %s", t.cfgPath)
   136→	}
   137→
   138→	files, err := os.ReadDir(t.cfgPath)
   139→	if err != nil {
   140→		return fmt.Errorf("error reading app folder: %#v", err)
   141→	}
   142→
   143→	for _, fn := range files {
   144→		if fn.IsDir() {
   145→			continue
   146→		}
   147→		fns := fn.Name()
   148→		cclog.Debugf("Process: %s", fns)
   149→		f, err := os.Open(filepath.Join(t.cfgPath, fns))
